package integration_test

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/build/testing/integration"
	"go.flipt.io/flipt/rpc/flipt"
	rpcevaluation "go.flipt.io/flipt/rpc/flipt/evaluation"
	sdk "go.flipt.io/flipt/sdk/go"
	"google.golang.org/protobuf/encoding/protojson"
)

// TestBooleanFlagEvaluation tests successful evaluation of a boolean flag.
func TestBooleanFlagEvaluation(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a boolean flag
		flag, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "boolean-flag",
			Name:         "Boolean Flag",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)
		assert.Equal(t, "boolean-flag", flag.Key)

		// Build the evaluation request
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "test-request-1",
			NamespaceKey: opts.Namespace,
			FlagKey:      "boolean-flag",
			EntityId:     "user123",
			Context: map[string]string{
				"device": "mobile",
			},
		}

		// Marshal request to JSON
		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		// Make HTTP request to evaluate endpoint
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Assert response status
		require.Equal(t, http.StatusOK, resp.StatusCode)

		// Read and unmarshal response
		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var boolResp rpcevaluation.BooleanEvaluationResponse
		err = protojson.Unmarshal(respBody, &boolResp)
		require.NoError(t, err)

		// Verify response fields
		assert.Equal(t, "test-request-1", boolResp.RequestId)
		assert.Equal(t, "boolean-flag", boolResp.FlagKey)
		assert.True(t, boolResp.Enabled)
		assert.NotZero(t, boolResp.RequestDurationMillis)
	})
}

// TestVariantFlagEvaluation tests successful evaluation of a variant flag.
func TestVariantFlagEvaluation(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a variant flag
		flag, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "variant-flag",
			Name:         "Variant Flag",
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create variants
		variantA, err := sdk.Flipt().CreateVariant(ctx, &flipt.CreateVariantRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			Key:          "variant-a",
			Name:         "Variant A",
		})
		require.NoError(t, err)

		variantB, err := sdk.Flipt().CreateVariant(ctx, &flipt.CreateVariantRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			Key:          "variant-b",
			Name:         "Variant B",
		})
		require.NoError(t, err)

		// Create a segment
		segment, err := sdk.Flipt().CreateSegment(ctx, &flipt.CreateSegmentRequest{
			NamespaceKey: opts.Namespace,
			Key:          "test-segment",
			Name:         "Test Segment",
			MatchType:    flipt.MatchType_ALL_MATCH_TYPE,
		})
		require.NoError(t, err)

		// Create a rule
		rule, err := sdk.Flipt().CreateRule(ctx, &flipt.CreateRuleRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			SegmentKey:   "test-segment",
			Rank:         1,
		})
		require.NoError(t, err)

		// Create a distribution for the rule
		_, err = sdk.Flipt().CreateDistribution(ctx, &flipt.CreateDistributionRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			RuleId:       rule.Id,
			VariantId:    variantA.Id,
			Rollout:      100.0,
		})
		require.NoError(t, err)

		// Build the evaluation request
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "test-variant-request",
			NamespaceKey: opts.Namespace,
			FlagKey:      "variant-flag",
			EntityId:     "user456",
			Context: map[string]string{
				"plan": "premium",
			},
		}

		// Marshal request to JSON
		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		// Make HTTP request
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/variant", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Assert response status
		require.Equal(t, http.StatusOK, resp.StatusCode)

		// Read and unmarshal response
		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var variantResp rpcevaluation.VariantEvaluationResponse
		err = protojson.Unmarshal(respBody, &variantResp)
		require.NoError(t, err)

		// Verify response fields
		assert.Equal(t, "test-variant-request", variantResp.RequestId)
		assert.Equal(t, "variant-flag", variantResp.FlagKey)
		assert.True(t, variantResp.Match)
		assert.NotEmpty(t, variantResp.VariantKey)
		assert.NotZero(t, variantResp.RequestDurationMillis)

		_ = flag
		_ = variantB
		_ = segment
	})
}

// TestFlagNotFound tests that evaluating a non-existent flag returns appropriate error.
func TestFlagNotFound(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		// Build evaluation request for a flag that doesn't exist
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "test-not-found",
			NamespaceKey: opts.Namespace,
			FlagKey:      "non-existent-flag",
			EntityId:     "user789",
		}

		// Marshal request to JSON
		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		// Make HTTP request
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Assert error status (should be 4xx or 5xx)
		assert.NotEqual(t, http.StatusOK, resp.StatusCode)

		// Verify we get an error response
		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)
		assert.NotEmpty(t, respBody)
	})
}

// TestInvalidFlagType tests that using wrong endpoint for flag type returns error.
func TestInvalidFlagType(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a boolean flag
		_, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "boolean-only-flag",
			Name:         "Boolean Flag",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Build evaluation request for variant endpoint (wrong endpoint for boolean flag)
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "test-wrong-type",
			NamespaceKey: opts.Namespace,
			FlagKey:      "boolean-only-flag",
			EntityId:     "user999",
		}

		// Marshal request to JSON
		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		// Make HTTP request to variant endpoint (which expects variant flag)
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/variant", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Should return an error
		assert.NotEqual(t, http.StatusOK, resp.StatusCode)
	})
}

// TestInvalidRequestBody tests that malformed JSON request returns 400 error.
func TestInvalidRequestBody(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		// Send malformed JSON
		malformedJSON := []byte(`{"invalid": json}`)

		// Make HTTP request with invalid JSON
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(malformedJSON),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Should return 400 or similar error status
		assert.True(t, resp.StatusCode >= 400 && resp.StatusCode < 500,
			"Expected 4xx status code for invalid JSON, got %d", resp.StatusCode)
	})
}

// TestBatchEvaluation tests batch evaluation of multiple flags.
func TestBatchEvaluation(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create first boolean flag
		_, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "batch-bool-1",
			Name:         "Batch Boolean 1",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create second boolean flag
		_, err = sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "batch-bool-2",
			Name:         "Batch Boolean 2",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      false,
		})
		require.NoError(t, err)

		// Build batch evaluation request
		batchReq := &rpcevaluation.BatchEvaluationRequest{
			RequestId: "batch-test-1",
			Requests: []*rpcevaluation.EvaluationRequest{
				{
					RequestId:    "req-1",
					NamespaceKey: opts.Namespace,
					FlagKey:      "batch-bool-1",
					EntityId:     "batch-user-1",
				},
				{
					RequestId:    "req-2",
					NamespaceKey: opts.Namespace,
					FlagKey:      "batch-bool-2",
					EntityId:     "batch-user-2",
				},
				{
					RequestId:    "req-3",
					NamespaceKey: opts.Namespace,
					FlagKey:      "non-existent-flag",
					EntityId:     "batch-user-3",
				},
			},
		}

		// Marshal request to JSON
		reqBytes, err := protojson.Marshal(batchReq)
		require.NoError(t, err)

		// Make HTTP request to batch endpoint
		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/batch", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Assert response status
		require.Equal(t, http.StatusOK, resp.StatusCode)

		// Read and unmarshal response
		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var batchResp rpcevaluation.BatchEvaluationResponse
		err = protojson.Unmarshal(respBody, &batchResp)
		require.NoError(t, err)

		// Verify we got responses for all requests
		assert.Equal(t, 3, len(batchResp.Responses))

		// Verify first response (successful boolean evaluation)
		assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[0].Type)
		assert.NotNil(t, batchResp.Responses[0].GetBooleanResponse())
		assert.True(t, batchResp.Responses[0].GetBooleanResponse().Enabled)

		// Verify second response (boolean evaluation)
		assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[1].Type)
		assert.NotNil(t, batchResp.Responses[1].GetBooleanResponse())
		assert.False(t, batchResp.Responses[1].GetBooleanResponse().Enabled)

		// Verify third response (error response for missing flag)
		assert.Equal(t, rpcevaluation.EvaluationResponseType_ERROR_EVALUATION_RESPONSE_TYPE, batchResp.Responses[2].Type)
		assert.NotNil(t, batchResp.Responses[2].GetErrorResponse())
		assert.Equal(t, rpcevaluation.ErrorEvaluationReason_NOT_FOUND_ERROR_EVALUATION_REASON,
			batchResp.Responses[2].GetErrorResponse().Reason)
	})
}

// TestNamespaceScoping tests that flags in different namespaces are isolated.
func TestNamespaceScoping(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a namespace-specific flag
		_, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "scoped-flag",
			Name:         "Scoped Flag",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create second namespace if not using default
		testNamespace := opts.Namespace
		if opts.Namespace == "default" {
			// Create a separate namespace
			ns, err := sdk.Flipt().CreateNamespace(ctx, &flipt.CreateNamespaceRequest{
				Key:  "other-namespace",
				Name: "Other Namespace",
			})
			require.NoError(t, err)
			testNamespace = ns.Key
		}

		// Evaluate the flag in the correct namespace
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "scoped-req-1",
			NamespaceKey: opts.Namespace,
			FlagKey:      "scoped-flag",
			EntityId:     "scoped-user",
		}

		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Should succeed in the correct namespace
		require.Equal(t, http.StatusOK, resp.StatusCode)

		// Now try to evaluate the same flag from a different namespace
		evalReq2 := &rpcevaluation.EvaluationRequest{
			RequestId:    "scoped-req-2",
			NamespaceKey: testNamespace,
			FlagKey:      "scoped-flag",
			EntityId:     "scoped-user",
		}

		reqBytes2, err := protojson.Marshal(evalReq2)
		require.NoError(t, err)

		resp2, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes2),
		)
		require.NoError(t, err)
		defer resp2.Body.Close()

		// Should fail (flag doesn't exist in other namespace)
		assert.NotEqual(t, http.StatusOK, resp2.StatusCode)
	})
}

// TestEvaluationWithContext tests that context is passed through evaluation.
func TestEvaluationWithContext(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a variant flag with context-based rule
		flag, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "context-flag",
			Name:         "Context Flag",
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
			Enabled:      true,
		})
		require.NoError(t, err)

		// Create variants
		variantA, err := sdk.Flipt().CreateVariant(ctx, &flipt.CreateVariantRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      flag.Key,
			Key:          "var-a",
			Name:         "Variant A",
		})
		require.NoError(t, err)

		// Create a segment with context constraint
		segment, err := sdk.Flipt().CreateSegment(ctx, &flipt.CreateSegmentRequest{
			NamespaceKey: opts.Namespace,
			Key:          "context-segment",
			Name:         "Context Segment",
			MatchType:    flipt.MatchType_ALL_MATCH_TYPE,
		})
		require.NoError(t, err)

		// Create a constraint that matches on context
		_, err = sdk.Flipt().CreateConstraint(ctx, &flipt.CreateConstraintRequest{
			NamespaceKey: opts.Namespace,
			SegmentKey:   segment.Key,
			Type:         flipt.ComparisonType_STRING_COMPARISON_TYPE,
			Property:     "environment",
			Operator:     "eq",
			Value:        "production",
		})
		require.NoError(t, err)

		// Create a rule for the segment
		rule, err := sdk.Flipt().CreateRule(ctx, &flipt.CreateRuleRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      flag.Key,
			SegmentKey:   segment.Key,
			Rank:         1,
		})
		require.NoError(t, err)

		// Create a distribution
		_, err = sdk.Flipt().CreateDistribution(ctx, &flipt.CreateDistributionRequest{
			NamespaceKey: opts.Namespace,
			FlagKey:      flag.Key,
			RuleId:       rule.Id,
			VariantId:    variantA.Id,
			Rollout:      100.0,
		})
		require.NoError(t, err)

		// Evaluate with matching context
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "context-req",
			NamespaceKey: opts.Namespace,
			FlagKey:      flag.Key,
			EntityId:     "context-user",
			Context: map[string]string{
				"environment": "production",
			},
		}

		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/variant", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		require.Equal(t, http.StatusOK, resp.StatusCode)

		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var variantResp rpcevaluation.VariantEvaluationResponse
		err = protojson.Unmarshal(respBody, &variantResp)
		require.NoError(t, err)

		// With matching context, should match
		assert.True(t, variantResp.Match)
		assert.Equal(t, "var-a", variantResp.VariantKey)
	})
}

// TestDisabledFlagEvaluation tests evaluation of a disabled flag.
func TestDisabledFlagEvaluation(t *testing.T) {
	integration.Harness(t, func(t *testing.T, sdk sdk.SDK, opts integration.TestOpts) {
		ctx := context.Background()

		// Create a disabled boolean flag
		flag, err := sdk.Flipt().CreateFlag(ctx, &flipt.CreateFlagRequest{
			NamespaceKey: opts.Namespace,
			Key:          "disabled-flag",
			Name:         "Disabled Flag",
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			Enabled:      false,
		})
		require.NoError(t, err)
		assert.False(t, flag.Enabled)

		// Evaluate the disabled flag
		evalReq := &rpcevaluation.EvaluationRequest{
			RequestId:    "disabled-req",
			NamespaceKey: opts.Namespace,
			FlagKey:      "disabled-flag",
			EntityId:     "disabled-user",
		}

		reqBytes, err := protojson.Marshal(evalReq)
		require.NoError(t, err)

		resp, err := http.Post(
			fmt.Sprintf("%s/evaluate/v1/boolean", opts.Addr),
			"application/json",
			bytes.NewReader(reqBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		require.Equal(t, http.StatusOK, resp.StatusCode)

		respBody, err := io.ReadAll(resp.Body)
		require.NoError(t, err)

		var boolResp rpcevaluation.BooleanEvaluationResponse
		err = protojson.Unmarshal(respBody, &boolResp)
		require.NoError(t, err)

		// Disabled flag should return false
		assert.False(t, boolResp.Enabled)
		assert.Equal(t, rpcevaluation.EvaluationReason_FLAG_DISABLED_EVALUATION_REASON, boolResp.Reason)
	})
}

